{"code":"import json, subprocess, sys, os
from email.utils import parsedate_to_datetime
from datetime import timezone, timedelta

GAPI = os.path.expanduser('~/.hermes/skills/productivity/google-workspace/scripts/google_api.py')
ENV = os.environ.copy()
ENV.update({
    'PATH': '/usr/bin:/bin:/root/.local/bin',
    'HERMES_GWS_BIN': '/root/.local/bin/gws',
    'HOME': '/root',
    'HERMES_HOME': '/root/.hermes',
})
TZ_VN = timezone(timedelta(hours=7))

def run(args):
    p = subprocess.run([sys.executable, GAPI] + args, capture_output=True, text=True, env=ENV)
    if p.returncode != 0:
        raise SystemExit(f'CMD FAILED: {args}\nSTDOUT:{p.stdout}\nSTDERR:{p.stderr}')
    try:
        return json.loads(p.stdout)
    except Exception:
        raise SystemExit(f'JSON parse failed for {args}\nSTDOUT:{p.stdout}\nSTDERR:{p.stderr}')

def fmt_date(s):
    try:
        return parsedate_to_datetime(s).astimezone(TZ_VN).strftime('%Y-%m-%d %H:%M')
    except Exception:
        return s

def clean_body(text, max_len=700):
    if not text:
        return ''
    lines = []
    for line in text.splitlines():
        line = line.strip()
        if not line:
            continue
        low = line.lower()
        if any(marker in low for marker in [
            'unsubscribe', 'click here', 'view in browser', 'privacy policy',
            '©', 'copyright', 'all rights reserved', 'sent from my', 'get outlook',
            '________________________________', '---', '___',
            'https://', 'http://', 'www.',
        ]):
            continue
        lines.append(line)
    text = '\n'.join(lines)
    if len(text) > max_len:
        text = text[:max_len] + '...'
    return text

def fetch_folder(folder):
    query = f'in:{folder} after:2026/04/21 before:2026/04/24'
    items = run(['gmail', 'search', query, '--max', '100'])
    out = []
    for msg in items:
        full = run(['gmail', 'get', msg['id']])
        out.append({
            'id': msg.get('id'),
            'subject': msg.get('subject',''),
            'from': msg.get('from',''),
            'to': msg.get('to',''),
            'date_raw': msg.get('date',''),
            'date_vn': fmt_date(msg.get('date','')),
            'snippet': msg.get('snippet',''),
            'body': clean_body(full.get('body') or msg.get('snippet','')),
            'labels': msg.get('labels',[]),
        })
    out.sort(key=lambda x: x['date_vn'], reverse=True)
    return out

result = {'inbox': fetch_folder('inbox'), 'sent': fetch_folder('sent')}
print(json.dumps(result, ensure_ascii=False, indent=2))
