{"code":"import json, subprocess, sys, os
from email.utils import parsedate_to_datetime
from datetime import timezone, timedelta, datetime

GAPI = os.path.expanduser('~/.hermes/skills/productivity/google-workspace/scripts/google_api.py')
ENV = os.environ.copy()
ENV.update({'PATH':'/usr/bin:/bin:/root/.local/bin','HERMES_GWS_BIN':'/root/.local/bin/gws','HOME':'/root','HERMES_HOME':'/root/.hermes'})
TZ_VN = timezone(timedelta(hours=7))
START = datetime(2026,4,22,0,0,tzinfo=TZ_VN)

def run(args):
    p = subprocess.run([sys.executable, GAPI] + args, capture_output=True, text=True, env=ENV)
    if p.returncode != 0:
        raise SystemExit(p.stderr or p.stdout)
    return json.loads(p.stdout)

def dt_vn(s):
    return parsedate_to_datetime(s).astimezone(TZ_VN)

def clean_body(text, max_len=320):
    if not text:
        return ''
    lines=[]
    for line in text.splitlines():
        line=line.strip()
        if not line: continue
        low=line.lower()
        if any(m in low for m in ['unsubscribe','click here','view in browser','privacy policy','©','copyright','all rights reserved','sent from my','get outlook','________________________________','---','___','https://','http://','www.']):
            continue
        lines.append(line)
    text=' '.join(lines)
    return text[:max_len] + ('...' if len(text)>max_len else '')

def fetch(folder):
    items = run(['gmail','search',f'in:{folder} after:2026/04/21 before:2026/04/24','--max','100'])
    out=[]
    for msg in items:
        dt=dt_vn(msg['date'])
        if dt < START:
            continue
        full = run(['gmail','get',msg['id']])
        out.append({
            'subject': msg.get('subject',''),
            'from': msg.get('from',''),
            'to': msg.get('to',''),
            'date': dt.strftime('%d/%m %H:%M'),
            'body': clean_body((full.get('body') or msg.get('snippet') or '')),
        })
    out.sort(key=lambda x: datetime.strptime('2026/'+x['date'], '%Y/%d/%m %H:%M'), reverse=True)
    return out

res={'inbox':fetch('inbox'),'sent':fetch('sent')}
print(json.dumps({'counts':{'inbox':len(res['inbox']),'sent':len(res['sent'])},'data':res},ensure_ascii=False,indent=2))
"}

