{"code":"import json, subprocess, re
cmd = 'lark-cli sheets +read --spreadsheet-token "SAAZsHPsahsUz3tQTiIlwUAIgKe" --range "JQtAeL!A1:A220" --as user'
res = subprocess.run(cmd, shell=True, capture_output=True, text=True)
data = json.loads(res.stdout)
rows = data['data']['valueRange']['values']
valid=[]
for r in rows[1:]:
    v = r[0] if r else None
    if not v or not isinstance(v, str):
        continue
    v=v.strip()
    if not v or len(v) < 4:
        continue
    if v.lower() in {'x','o'}:
        continue
    if ' ' not in v:
        continue
    valid.append(v)
# preserve order, dedupe
seen=set(); out=[]
for x in valid:
    if x not in seen:
        seen.add(x); out.append(x)
print(json.dumps({'count':len(out),'employees':out}, ensure_ascii=False, indent=2))
"}

